WITH start_v AS (SELECT v.id FROM ways_vertices_pgr v ORDER BY (SELECT geom FROM mission_pois WHERE role = 'attaque' LIMIT 1) <-> v.geom LIMIT 1), dd AS (SELECT node, agg_cost FROM pgr_drivingdistance('SELECT id, source, target, cost, reverse_cost FROM ways WHERE cost IS NOT NULL', (SELECT id FROM start_v), 5000, directed := false)), edges AS (SELECT w.id, w.source, w.target, w.nature FROM ways w WHERE w.source IN (SELECT node FROM dd) AND w.target IN (SELECT node FROM dd)) SELECT nature, count(*) AS nb FROM edges GROUP BY nature ORDER BY nb DESC LIMIT 10;
